# board/__init__.py
from .board import Board

# board/board.py

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('white')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('black')

    def get_piece(self, row, col):
        return self.board[row][col]

    def move_piece(self, from_row, from_col, to_row, to_col):
        piece = self.get_piece(from_row, from_col)
        if piece is None:
            raise ValueError("No piece at the source position")
        self.board[from_row][from_col] = None
        self.board[to_row][to_col] = piece
        return self.check_captures(to_row, to_col)

    def check_captures(self, row, col):
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        captures = []
        for dr, dc in directions:
            if self.is_valid_move(row + dr * 2, col + dc * 2, row, col, dr, dc):
                captures.append((row + dr, col + dc))
        return captures

    def is_valid_move(self, to_row, to_col, from_row, from_col, dr, dc):
        piece = self.get_piece(from_row, from_col)
        if not piece:
            return False
        if abs(dr) != 1 or abs(dc) != 1:
            return False
        if self.get_piece(to_row, to_col) is not None:
            return False
        intermediate_piece = self.get_piece(from_row + dr, from_col + dc)
        if intermediate_piece is None:
            return True
        return intermediate_piece.color != piece.color and (abs(dr) == 2 or self.is_valid_move(to_row, to_col, from_row + dr, from_col + dc, dr, dc))
