# game/__init__.py
from .game import Game

# game/game.py

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'white'
        self.turn_count = 0

    def switch_turn(self):
        self.current_player = 'black' if self.current_player == 'white' else 'white'

    def get_board_state(self):
        return self.board.board

    def make_move(self, from_row, from_col, to_row, to_col):
        captures = self.board.move_piece(from_row, from_col, to_row, to_col)
        self.turn_count += 1
        if len(captures) > 0:
            self.make_captures(captures, from_row, from_col, to_row, to_col)

    def make_captures(self, captures, from_row, from_col, to_row, to_col):
        for capture in captures:
            capture_piece = self.board.get_piece(*capture)
            if capture_piece:
                self.board.board[capture[0]][capture[1]] = None

    def check_winner(self):
        if self.turn_count >= 56:  # Assuming game ends after 28 turns
            return "Draw"
        white_pieces = sum(row.count('W') + row.count('Wk') for row in self.board.board)
        black_pieces = sum(row.count('B') + row.count('Bk') for row in self.board.board)
        if white_pieces == 0:
            return 'Black wins'
        elif black_pieces == 0:
            return 'White wins'
        return None
